     2|import { useEffect, useRef, useState, type ReactNode } from "react"
     3|
     4|export function FadeUp({ children, delay = 0 }: { children: ReactNode; delay?: number }) {
     5|  const ref = useRef<HTMLDivElement>(null)
     6|  const [visible, setVisible] = useState(false)
     7|
     8|  useEffect(() => {
     9|    const observer = new IntersectionObserver(
    10|      ([entry]) => { if (entry.isIntersecting) { setVisible(true); observer.disconnect() } },
    11|      { threshold: 0.1 }
    12|    )
    13|    if (ref.current) observer.observe(ref.current)
    14|    return () => observer.disconnect()
    15|  }, [])
    16|
    17|  return (
    18|    <div ref={ref} className={`transition-all duration-700 ${visible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-6"}`}
    19|      style={{ transitionDelay: `${delay}ms` }}>
    20|      {children}
    21|    </div>
    22|  )
    23|}
    24|
    25|export function StaggerGrid({ children }: { children: ReactNode }) {
    26|  return <>{children}</>
    27|}
    28|
    29|export function StaggerItem({ children, index = 0 }: { children: ReactNode; index?: number }) {
    30|  return <FadeUp delay={index * 100}>{children}</FadeUp>
    31|}
